package ElementsTypesOfVariables;

public class LocalVariable {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//local variables are declare inside a method
		//local variables are stored in side stack area
		//the scope of local variable is method level
		//among other variable local  variables are fast because they are stored in stack area
		String myName="Afrin";
		long myPhoneNumber=7013491025L;
		String myEmail="shaikafrin750@gmail.com";
		
		
		System.out.println(myPhoneNumber);
		System.out.println(myEmail);
		System.out.println(myName);
		

	}

}
